(function(){"use strict";if(!document.getElementById("jf-menu-anims")){const s=document.createElement("style");s.id="jf-menu-anims";s.textContent=".btnApplicationMenu, .btnHeaderMenu, .barsMenuButton, .btnCloseMenu { transition: transform 0.2s ease !important; } .btnApplicationMenu:hover, .btnHeaderMenu:hover, .barsMenuButton:hover, .btnCloseMenu:hover { transform: scale(1.15) !important; } .btnApplicationMenu:active, .btnHeaderMenu:active, .barsMenuButton:active, .btnCloseMenu:active { transform: scale(0.9) !important; } .btnApplicationMenu .material-icons, .btnHeaderMenu .material-icons, .barsMenuButton .material-icons, .btnCloseMenu .material-icons { transition: transform 0.35s cubic-bezier(0.4, 0, 0.2, 1) !important; } .btnApplicationMenu:hover .material-icons, .btnHeaderMenu:hover .material-icons, .barsMenuButton:hover .material-icons, .btnCloseMenu:hover .material-icons { transform: rotate(180deg) !important; }";document.head.appendChild(s)}const r=()=>{const c=document.querySelector(".customMenuOptions"),h=document.querySelector('.mainDrawer-scrollContainer > a[href="#/home"]'),s=document.querySelector(".mainDrawer-scrollContainer");if(c){if(!c.querySelector(".sidebarHeader")){const d=document.createElement("h3");d.className="sidebarHeader";d.textContent="General";c.appendChild(d)}if(h)c.appendChild(h)}if(s&&!document.querySelector(".btnCloseMenuContainer")){const x=document.createElement("div");x.className="btnCloseMenuContainer";x.style.display="flex";x.style.justifyContent="flex-end";x.style.padding="8px 16px 0 0";const b=document.createElement("button");b.type="button";b.setAttribute("is","paper-icon-button-light");b.className="headerButton mainDrawerButton barsMenuButton headerButtonLeft paper-icon-button-light btnCloseMenu";b.title="Close Menu";b.innerHTML='<span class="material-icons" aria-hidden="true">close</span>';b.addEventListener("click",e=>{e.preventDefault();e.stopPropagation();const p=document.querySelector(".mainDrawer-backdrop, .drawer-backdrop");if(p){p.click();return}const t=document.querySelector(".btnApplicationMenu, .btnHeaderMenu, .mainDrawerButton:not(.btnCloseMenu)");if(t)t.click()});x.appendChild(b);s.insertBefore(x,s.firstChild)}};r();const o=new MutationObserver(m=>{for(let i=0;i<m.length;i++){const a=m[i].addedNodes;for(let j=0;j<a.length;j++){const n=a[j];if(n.nodeType===1){if(n.classList.contains("mainDrawer-scrollContainer")||n.classList.contains("customMenuOptions")||n.querySelector(".customMenuOptions")){r();return}}}}});o.observe(document.body,{childList:!0,subtree:!0})})();
